@import "tailwindcss";

@theme {
  /* palette (mined, ranked by usage) */
  --color-neutral-50: #ffffff;
  --color-neutral-100: #e6e6e6;
  --color-neutral-200: #d7d7da;
  --color-neutral-300: #cccccc;
  --color-neutral-400: #b3b3b3;
  --color-neutral-500: #999999;
  --color-neutral-600: #88898c;
  --color-neutral-700: #666666;
  --color-neutral-800: #4d4d4d;
  --color-neutral-900: #333333;
  --color-neutral-950: #1a1a1a;
  --color-blue: #1a44ea;
  --color-pale-blue: #f1f1f4;
  --color-red: #fc4040;
  --color-cyan: #178bff;
  --color-green: #10c47f;
  --color-orange: #f4882a;
  --color-green-2: #197e10;
  --color-orange-2: #ac5102;
  --color-red-2: #ba171f;
  --color-deep-cyan: #0b335b;
  --color-deep-cyan-2: #10263d;
  --color-deep-green: #0b5b3c;

  /* inferred semantic roles (each maps to a distinct mined value) */
  --color-canvas: #ffffff;
  --color-ink: #1a1a1a;
  --color-text-muted: #999999;
  --color-surface: #e6e6e6;
  --color-hairline: #d7d7da;
  --color-accent: #1a44ea;
  --color-accent-2: #f1f1f4;
  --color-accent-3: #fc4040;

  --font-sans: "Porsche Next", ui-sans-serif, system-ui, sans-serif;

  --text-xs: 0.6875rem;
  --text-sm: 0.75rem;
  --text-base: 0.875rem;
  --text-lg: 1rem;
  --text-xl: 1.375rem;

  --font-weight-normal: 400;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  /* line-heights, sorted tight -> loose */
  --leading-none: 1;
  --leading-tight: 1.1;
  --leading-snug: 1.3;
  --leading-normal: 1.5;

  /* letter-spacing, sorted tight -> wide */
  --tracking-tightest: .05em;

  --radius-sm: 1px;
  --radius-md: 4px;
  --radius-lg: 8px;
  --radius-xl: 10px;
  --radius-2xl: 12px;
  --radius-3xl: 32px;
  --radius-4xl: 100%;
  --radius-full: 50%;

  /* shadows, sorted by blur */
  --shadow-sm: 0 8px 40px #00000029;
  --shadow-md: 0 3px 8px #00000029;

  --breakpoint-sm: 23.4375rem;
  --breakpoint-md: 24.375rem;
  --breakpoint-lg: 29.9375rem;
  --breakpoint-xl: 30rem;
  --breakpoint-2xl: 47.4375rem;
  --breakpoint-3xl: 47.5rem;
  --breakpoint-4xl: 47.9375rem;
  --breakpoint-5xl: 48rem;

  /* most-used spacing values on the source site (px): 1, 2, 3, 4, 6, 8, 10, 12, 16, 20, 36, 80 */
}

/* dark-mode values mined from the source (native token names) */
@media (prefers-color-scheme: dark) {
  :root {
    --p-color-canvas: #010205;
    --p-color-surface: #19191a;
    --p-color-frosted: hsla(240,2%,43%,.228);
    --p-color-frosted-soft: rgba(65,65,70,.154);
    --p-color-frosted-strong: rgba(156,156,159,.302);
    --p-color-backdrop: rgba(36,36,40,.5);
    --p-color-primary: #fafbff;
    --p-color-contrast-higher: rgba(246,246,248,.78);
    --p-color-contrast-high: rgba(246,246,248,.67);
    --p-color-contrast-medium: rgba(246,246,248,.56);
    --p-color-contrast-low: rgba(246,246,248,.45);
    --p-color-contrast-lower: rgba(156,156,159,.302);
    --p-color-info: #178bff;
    --p-color-info-medium: rgba(23,139,255,.6);
    --p-color-info-low: rgba(23,139,255,.18);
    --p-color-info-frosted: rgba(11,51,91,.66);
    --p-color-info-frosted-soft: rgba(16,38,61,.66);
    --p-color-success: #10c47f;
    --p-color-success-medium: rgba(16,196,127,.6);
    --p-color-success-low: rgba(16,196,127,.18);
    --p-color-success-frosted: rgba(11,91,60,.66);
    --p-color-success-frosted-soft: rgba(16,61,44,.66);
    --p-color-warning: #f4882a;
    --p-color-warning-medium: rgba(244,136,42,.6);
    --p-color-warning-low: rgba(244,136,42,.18);
    --p-color-warning-frosted: rgba(91,81,11,.66);
    --p-color-warning-frosted-soft: rgba(61,55,16,.66);
    --p-color-error: #fc4040;
    --p-color-error-medium: rgba(252,64,64,.6);
    --p-color-error-low: rgba(252,64,64,.18);
    --p-color-error-frosted: rgba(91,11,11,.66);
    --p-color-error-frosted-soft: rgba(61,16,16,.66);
    --p-color-focus: #1a44ea;
  }
}

